import { Component } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

@Component({
  selector: 'app-article',
  template: `<article [innerHTML]="safeBody"></article>`,
})
export class ArticleComponent {
  safeBody: SafeHtml;

  constructor(private sanitizer: DomSanitizer) {
    const rawHtml = '<p>Content from <strong>CMS</strong></p>';
    // Angular sanitises by default; mark as trusted only if you control the source
    this.safeBody = this.sanitizer.bypassSecurityTrustHtml(rawHtml);
  }
}

// app.component.ts
import { Component, OnInit, ViewChild, ElementRef } from '@angular/core';
import { Router, NavigationEnd } from '@angular/router';
import { filter } from 'rxjs/operators';

@Component({
  selector: 'app-root',
  template: `
    <h1 #mainHeading tabindex="-1">{{ currentTitle }}</h1>
    <router-outlet />
  `,
})
export class AppComponent implements OnInit {
  @ViewChild('mainHeading') mainHeading!: ElementRef<HTMLHeadingElement>;
  currentTitle = 'My App';

  constructor(private router: Router) {}

  ngOnInit() {
    this.router.events
      .pipe(filter(e => e instanceof NavigationEnd))
      .subscribe(() => {
        // Update title and move focus so screen readers announce the new page
        this.mainHeading.nativeElement.focus();
      });
  }
}

// Paste in DevTools console to inspect heading outline
document.querySelectorAll('h1, h2, h3, h4, h5, h6').forEach(el => {
  console.log(`${'  '.repeat(Number(el.tagName[1]) - 1)}${el.tagName}: ${el.textContent.trim()}`);
});

// article.component.spec.ts
import { ComponentFixture, TestBed } from '@angular/core/testing';
import { ArticleComponent } from './article.component';

describe('ArticleComponent', () => {
  let fixture: ComponentFixture<ArticleComponent>;

  beforeEach(() => {
    TestBed.configureTestingModule({ declarations: [ArticleComponent] });
    fixture = TestBed.createComponent(ArticleComponent);
    fixture.componentInstance.title = 'Introduction to Components';
    fixture.detectChanges();
  });

  it('renders the article title in an h1', () => {
    const h1 = fixture.nativeElement.querySelector('h1');
    expect(h1?.textContent).toContain('Introduction to Components');
  });

  it('has no h3 without a preceding h2', () => {
    const headings = fixture.nativeElement.querySelectorAll('h1, h2, h3, h4, h5, h6');
    let lastLevel = 0;
    headings.forEach((el: HTMLElement) => {
      const level = Number(el.tagName[1]);
      expect(level).toBeLessThanOrEqual(lastLevel + 1);
      lastLevel = level;
    });
  });
});

/* styles.css (global Angular styles) */
h1, h2, h3, h4, h5, h6 {
  margin: 0;
  font-size: inherit;   /* let the design system set sizes */
  font-weight: inherit; /* let the design system set weight */
  line-height: 1.2;
}

p {
  margin: 0 0 1rem;     /* single bottom margin, no top */
}
